export const CARDS_DOBOKU = [
  { id: 32, category: "doboku_haisui", source: "jac-ch3", furi: "きゅうはいすいこうじ", jp: "給排水工事", romaji: "kyuu haisui kouji", id_text: "Pekerjaan suplai air dan drainase", desc: "Suplai: air sungai → pemurnian → reservoir → pipa. Drainase: limbah gedung → pipa → instalasi pengolahan.", _origIndex: 30 },
  { id: 47, category: "doboku_hoso", source: "jac-ch4", furi: "てんあつ", jp: "転圧（てんあつ）", romaji: "ten'atsu", id_text: "Pemadatan dengan roller", desc: "Proses memadatkan tanah/aspal menggunakan roller. Digunakan dalam pekerjaan perkerasan jalan (舗装工事).", _origIndex: 45 },
  { id: 48, category: "doboku_hoso", source: "jac-ch3", furi: "ろしょうろばんひょうそう", jp: "路床・路盤・表層（舗装工事の層構造）", romaji: "roshou / roban / hyousou", id_text: "Lapisan jalan: subgrade / base / surface", desc: "Dari bawah: ①路床 (subgrade, digali ±1m) ②路盤 (batu pecah, dipadatkan roller) ③表層 (aspal atas, tahan air).", _origIndex: 46 },
  { id: 49, category: "doboku_doko", source: "jac-ch4", furi: "やりかたみずぬきみずもり", jp: "遣り方（やりかた）・水貫・水盛り", romaji: "yarikata / mizunuki / mizumori", id_text: "Setting out bangunan — tiang & papan referensi", desc: "遣り方: rangka sementara tiang kayu + papan horizontal (水貫) untuk menentukan posisi & ketinggian bangunan. Di sipil disebut '丁張り'.", _origIndex: 47 },
  { id: 178, category: "doboku_doko", source: "jac-ch3", furi: "ちすいりすい", jp: "治水（ちすい）vs 利水（りすい）", romaji: "chisui vs risui", id_text: "Pengendalian banjir vs Pemanfaatan air", desc: "Dua tujuan utama bendungan (ダム). Chisui = menampung air saat hujan lebat agar sungai tidak meluap. Risui = menyediakan air stabil untuk pertanian, industri, dan PLTA.", _origIndex: 169 },
  { id: 179, category: "doboku_doko", source: "jac-ch3", furi: "ななとむこうほう", jp: "NATM（ナトム）工法", romaji: "NATM natomu kouhou", id_text: "Metode penggalian terowongan gunung", desc: "Metode terowongan gunung: bor/ledak batuan, semprotkan beton (吹付け), pasang penopang baja dan rock bolt. Mandor:「吹付け準備して」(siapkan beton semprot).", _origIndex: 170 },
  { id: 180, category: "doboku_doko", source: "jac-ch3", furi: "しいるどとんねるせぐめんと", jp: "シールドトンネル・セグメント", romaji: "shiirudo tonneru segumento", id_text: "Terowongan shield / segmen beton/baja", desc: "Shield machine menggali dari 立坑, lalu segmen beton/baja dipasang di belakang mesin sebagai dinding. Cocok untuk tanah lunak. Mandor:「セグメント組み立てて」(rakit segmennya).", _origIndex: 171 },
  { id: 182, category: "doboku_doko", source: "jac-ch3", furi: "きょうりょうこうじかぶこうじょうぶこう", jp: "橋梁工事（下部工・上部工）", romaji: "kyouryou kouji kabukou vs joubukou", id_text: "Pekerjaan jembatan: struktur bawah & atas", desc: "下部工=pondasi penopang jembatan. 上部工=badan jembatan untuk kendaraan/pejalan kaki. Mandor:「下部工の検査入ります」(inspeksi struktur bawah).", _origIndex: 173 },
  { id: 183, category: "doboku_doko", source: "jac-ch3", furi: "かいようどぼくこうじ", jp: "海洋土木工事（かいようどぼく）", romaji: "kaiyou doboku kouji", id_text: "Pekerjaan sipil laut / offshore civil work", desc: "Pembangunan pelabuhan, bandara, terowongan bawah laut, jembatan laut, dan turbin angin di laut. Menggunakan kapal kerja (作業船) untuk mengeruk atau mengangkat material, serta penyelam (潜水士).", _origIndex: 174 },
  { id: 184, category: "doboku_doko", source: "jac-ch3", furi: "しゅんせつこうじ", jp: "浚渫工事（しゅんせつ）", romaji: "shunsetsu kouji", id_text: "Pengerukan dasar laut/sungai", desc: "Mengangkat lumpur dan pasir dari dasar laut atau sungai menggunakan kapal keruk (浚渫船) agar kapal dapat berlayar dengan aman di jalur pelayaran dan sandar di pelabuhan.", _origIndex: 175 },
  { id: 185, category: "doboku_doko", source: "jac-ch3", furi: "けえそん", jp: "ケーソン（防波堤工事）", romaji: "keeson", id_text: "Caisson / kotak beton untuk pemecah gelombang", desc: "Kotak beton besar yang diletakkan di atas hamparan batu di dasar laut, lalu diisi pasir/kerikil untuk menstabilkan. Digunakan dalam pembuatan pemecah gelombang (防波堤).", _origIndex: 176 },
  { id: 187, category: "doboku_haisui", source: "jac-ch3", furi: "ぼおりんぐちょうさしじそう", jp: "ボーリング調査・支持層（しじそう）", romaji: "booringu chousa shijisou", id_text: "Penyelidikan tanah / lapisan pendukung pondasi", desc: "Pengeboran tanah (ボーリング) untuk menemukan lapisan keras (支持層) tempat ujung tiang harus mencapai. Juga deteksi rintangan bawah tanah. Mandor:「支持層まで何mか確認して」(cek kedalaman lapisan keras).", _origIndex: 178 },
  { id: 189, category: "doboku_haisui", source: "jac-ch3", furi: "くいこうじばしょうちくいきせいくい", jp: "杭工事", romaji: "kui kouji basho uchi kui vs kisei kui", id_text: "Pekerjaan tiang: cast-in-place vs precast", desc: "場所打ち杭=lubang digali, rangka tulangan dipasang, beton dicor di tempat. 既成杭=tiang pabrik (beton/baja/kayu) dipancang. Mandor:「既成杭の搬入確認して」(cek tiang pabrik masuk).", _origIndex: 180 },
  { id: 191, category: "doboku_doko", source: "jac-ch3", furi: "ねぎり", jp: "根切り（ねぎり）", romaji: "negiri", id_text: "Galian pondasi bangunan", desc: "Penggalian tanah di lokasi pondasi bangunan agar struktur bawah tanah bisa dibangun. Berbeda dari galian umum — 根切り spesifik untuk menanam fondasi gedung.", _origIndex: 182 },
  { id: 193, category: "doboku_doko", source: "jac-ch3", furi: "もりどきりど", jp: "盛り土（もりど）vs 切り土（きりど）", romaji: "morido vs kirido", id_text: "Penimbunan vs penggalian untuk meratakan lahan", desc: "盛り土 = tanah ditimbun pada lahan miring atau tidak rata agar menjadi datar. 切り土 = tanah dipotong/digali agar permukaan menjadi rata. Keduanya adalah bagian dari pekerjaan tanah (土工作業).", _origIndex: 184 },
  { id: 194, category: "doboku_doko", source: "jac-ch3", furi: "うめもどしさぎょう", jp: "埋め戻し作業（うめもどし）", romaji: "umemodoshi sagyou", id_text: "Pekerjaan pengurugan kembali", desc: "Setelah pekerjaan bawah tanah atau fondasi selesai, ruang kosong di sekitar struktur ditimbun kembali dengan tanah. Ini adalah tahap akhir dari pekerjaan galian.", _origIndex: 185 },
  { id: 195, category: "doboku_haisui", source: "jac-ch3", furi: "さくせいこうじしゅるい", jp: "さく井工事の4種類（水源・観測・温泉・地熱）", romaji: "sakusei kouji 4 shurui", id_text: "4 jenis pekerjaan pengeboran sumur", desc: "①水源井=air tanah. ②観測井=pantau penurunan tanah. ③温泉井=500〜1000m, bahaya gas. ④地熱井=±2000m, bahaya uap+panas. Mandor:「掘削深度の記録つけて」(catat kedalaman bor).", _origIndex: 186 },
  { id: 196, category: "doboku_haisui", source: "jac-ch3", furi: "ぢいぷうえる", jp: "ディープウェル（深井戸排水）", romaji: "diipu ueru", id_text: "Deep well dewatering / drainase sumur dalam", desc: "Metode pemompaan air tanah untuk galian di kedalaman >10m. Berbeda dari wellpoint (id:151) yang hanya efektif hingga ~10m. Untuk air tanah sangat dalam, ディープウェル adalah solusinya.", _origIndex: 187 },
  { id: 197, category: "doboku_doko", source: "jac-ch3", furi: "とびこうじのしゅるい", jp: "とび工事の種類", romaji: "tobi kouji no shurui", id_text: "Jenis pekerjaan tobi / rigger-scaffolder", desc: "足場とび=perancah, 鉄骨とび=rangka baja, 橋梁とび=jembatan, 重量とび=mesin berat, 送電とび=menara listrik, 町場とび=rumah. Mandor:「足場の点検してくれ」(cek perancah).", _origIndex: 188 },
  { id: 218, category: "doboku_doko", source: "jac-ch3", furi: "かいさくとんねる", jp: "開削トンネル（かいさくトンネル）", romaji: "kaisaku tonneru", id_text: "Cut-and-cover tunnel / terowongan gali-tutup", desc: "Tanah digali dari permukaan, terowongan dibangun dalam galian, lalu ditimbun kembali. Berbeda dari shield yang menggali horizontal. Mandor:「土留め支保工の点検して」(cek dinding penahan tanah).", _origIndex: 209 },
  { id: 219, category: "doboku_doko", source: "jac-ch3", furi: "のりめんこうじもるたるふきつけしょくせいこうほう", jp: "法面工事（のりめん）", romaji: "norimenkouji morutaru fukitsuke shokusei kouhou", id_text: "Perkuatan lereng: semprotan mortar & revegetasi", desc: "①モルタル吹付け=mortar disemprot ke lereng untuk stabilisasi. ②植生工法=mat benih+pupuk ditempel agar tanaman tumbuh menahan tanah. Mandor:「吹付けの厚さ確認して」(cek ketebalan semprotan mortar).", _origIndex: 210 },
  { id: 220, category: "doboku_doko", source: "jac-ch3", furi: "かせんかいがんこうぞうぶつぼうはていぼうちょうていごがんていぼうすいろ", jp: "河川・海岸の構造物", romaji: "kasen kaigan kouzoubutsu: bouhatei bouchoutei gogan teibou suiro", id_text: "Struktur sungai & pantai: tanggul, turap, saluran", desc: "防波堤=pecah gelombang pelabuhan. 防潮堤=tahan tsunami. 護岸=turap tepi sungai. 堤防=tanggul banjir. 水路=saluran irigasi/drainase. Mandor:「護岸の法面点検して」(cek lereng turap).", _origIndex: 211 },
  { id: 221, category: "doboku_doko", source: "jac-ch3", furi: "てつどうこうじたしょくしゅしゅうやくこうじ", jp: "鉄道工事（てつどう）", romaji: "tetsudou kouji ta-shokushu shuuyaku kouji", id_text: "Pekerjaan rel: gabungan semua keahlian konstruksi", desc: "多職種集約工事。Pekerjaan kereta mencakup hampir SEMUA jenis konstruksi: 土木+電気設備+建築+spesialis. Ini yang membuat kereta jadi proyek paling kompleks. Mandor:「各職種の工程調整してくれ」(koordinasi jadwal semua profesi).", _origIndex: 212 },
  { id: 222, category: "doboku_haisui", source: "jac-ch3", furi: "じょうげすいどうこうじじょうすいじょうげすいしょりじょう", jp: "上下水道工事", romaji: "jouge suidou kouji jousui jou gesui shori jou", id_text: "Instalasi air bersih & kotor: treatment plant", desc: "上水道: sungai→浄水場→pipa→rumah. 下水道: air kotor→下水処理場→sungai/laut. Termasuk pekerjaan lahan dan instalasi pipa. Mandor:「管の勾配ちゃんと確認して」(cek kemiringan pipa).", _origIndex: 213 },
  { id: 223, category: "doboku_doko", source: "jac-ch3", furi: "さいがいふっきゅうこうじ", jp: "災害復旧工事（さいがいふっきゅう）", romaji: "saigai fukkyuu kouji", id_text: "Pekerjaan pemulihan bencana", desc: "Jepang rutin mengalami kerusakan akibat topan, hujan, gempa. 災害復旧=perbaiki fasilitas sipil (sungai, jalan, pelabuhan) yang rusak dengan cepat. Mandor:「早急に復旧工事に取り掛かれ」(segera mulai perbaikan).", _origIndex: 214 },
  { id: 232, category: "doboku_doko", source: "jac-ch3", furi: "うめたてこうじがんぺきこうじ", jp: "埋立工事 vs 岸壁工事（うめたて・がんぺき）", romaji: "umetate kouji vs ganpeki kouji", id_text: "Reklamasi laut vs Konstruksi dermaga kapal", desc: "埋立=tanah pengerukan ditimbun ke laut untuk lahan baru (bandara, industri). 岸壁=dermaga kapal pakai sheet pile baja (鋼矢板) dan tiang. Mandor:「鋼矢板の打設確認して」(cek sheet pile).", _origIndex: 223 },
  { id: 234, category: "doboku_hoso", source: "jac-ch3", furi: "ほうそうそうろしょうろばんきそうひょうそうあすふるといにっしゃあ", jp: "舗装の4層", romaji: "housou 4sou: roshou roban kisou hyousou asufuruto finisshaa", id_text: "4 lapisan jalan: subgrade/base/binder/wearing", desc: "①路床=dasar terbawah. ②路盤=batu pecah dipadatkan. ③基層=aspal pertama (アスファルトフィニッシャー). ④表層=aspal atas, tahan air. Mandor:「路盤の締固め確認してから基層打って」(cek kepadatan base dulu).", _origIndex: 225 },
  { id: 235, category: "doboku_haisui", source: "jac-ch3", furi: "くいのざいりょうしゅるいきくいこうくいこんくりいとくい", jp: "杭の材料3種", romaji: "kui no zairyou 3 shurui: ki-kui kou-kui konkuriito-kui", id_text: "3 material tiang pondasi: kayu / baja / beton", desc: "木杭=kayu (tanah lunak). 鋼杭=baja (kuat, dalam). コンクリート杭=paling umum: 場所打ち atau 既成 (pabrik). Pilih per kondisi tanah, kedalaman支持層, kebisingan. Mandor:「支持層まで何mか報告して」(laporkan kedalaman keras).", _origIndex: 226 },
  { id: 247, category: "doboku_haisui", source: "jac-ch3", furi: "おんせんせいちねつせいふかさときけんせい", jp: "温泉井 vs 地熱井", romaji: "onsensei vs chinetsusei: fukasa to kikensei 500-1000m / 2000m", id_text: "Sumur panas vs panas bumi: kedalaman & bahaya", desc: "温泉井=500〜1000m, bahaya: gas alam keluar saat bor → perlu izin. 地熱井=±2000m (terdalam), bahaya: 熱水・蒸気・有害物質 → keahlian tertinggi. Mandor:「掘削中はガス検知器つけといて」(pasang detektor gas selama pengeboran).", _origIndex: 238 },
  { id: 254, category: "doboku_doko", source: "jac-ch4", furi: "じなわばりみずいと", jp: "地縄張り（じなわばり）・水糸（みずいと）", romaji: "jinawabari / mizuito", id_text: "Penandaan pondasi di tanah / benang referensi", desc: "地縄張り=menandai posisi pondasi di tanah dengan tali. 水糸=benang horizontal direntangkan antar papan 水貫 sebagai referensi sumbu bangunan. Mandor:「地縄と水糸を確認してから掘れ」.", _origIndex: 245 },
  { id: 256, category: "doboku_doko", source: "jac-ch4", furi: "もりどだんぎり", jp: "盛り土（もりど）・段切り（だんきり）", romaji: "morido / dangiri", id_text: "Timbunan tanah / Pemotongan tangga pada lereng", desc: "盛り土 = menimbun tanah untuk meratakan lahan yang tidak rata atau miring. 段切り = memotong lahan miring secara bertingkat seperti tangga sebelum menimbun, agar timbunan tidak longsor.", _origIndex: 247 },
  { id: 257, category: "doboku_doko", source: "jac-ch4", furi: "ねきりよぼりすきとりとこづけ", jp: "根切り・余堀り・鋤取り・床付け", romaji: "nekiri / yobori / sukitori / tokoduke", id_text: "Galian pondasi, galian lebih, perataan, dasar", desc: "根切り=gali hingga kedalaman pondasi. 余堀り=galian lebih untuk ruang kerja. 鋤取り=ratakan dasar. 床付け=finishing dasar secara presisi. Mandor:「床付けは丁寧にやれよ」.", _origIndex: 248 },
  { id: 258, category: "doboku_doko", source: "jac-ch4", furi: "うめもどしつきがためみずしめ", jp: "埋め戻し・突き固め・水締め", romaji: "umemodoshi / tsukigatame / mizushime", id_text: "Urugan balik / pemadatan manual / dengan air", desc: "埋め戻し=isi kembali tanah setelah pekerjaan bawah tanah. 突き固め=padatkan dengan ランマ. 水締め=tuang air sambil memadatkan. Mandor:「しっかり締め固めてくれ」.", _origIndex: 249 },
  { id: 319, category: "doboku_doko", source: "jac-ch4", furi: "くいまさらいだんばね", jp: "杭間さらい・段跳ね", romaji: "kui ma sarai / dan bane", id_text: "Penggalian di antara tiang / angkat tanah bertahap", desc: "杭間さらい=saat 床付け, ratakan tanah di antara tiang pondasi. 段跳ね=galian dalam, tanah diangkat bertahap ke atas melalui undakan. Mandor:「杭間さらいは基礎工事に影響するからちゃんとやれ」.", _origIndex: 310 },
  { id: 320, category: "doboku_doko", source: "jac-ch4", furi: "やまずな", jp: "山砂（やまずな）", romaji: "yama zuna", id_text: "Pasir gunung/daratan (berbeda dari pasir sungai)", desc: "Pasir dari daratan (bukan sungai). Daya serap air (保水性) lebih tinggi dari pasir sungai. Digunakan sebagai material urugan balik. Mandor:「山砂は保水性が高いから水締めをしっかりやってくれよ」.", _origIndex: 311 },
  { id: 321, category: "doboku_haisui", source: "jac-ch4", furi: "きせいくいこうほうばしょううちこんくりいとくいこうほう", jp: "既成杭工法 vs 場所打ちコン杭工法", romaji: "kisei kui kouhou vs bashouuchi konkuriito kui kouhou", id_text: "Tiang prefabrikasi vs tiang beton cor di tempat", desc: "既成杭=tiang dibuat di pabrik lalu dipancang. 場所打ち杭=lubang dibor di lokasi lalu dicor. Pilihan tergantung kondisi tanah dan beban. Mandor:「杭工法は地質調査の結果で決めるんだ」.", _origIndex: 312 },
  { id: 422, category: "doboku_doko", source: "jac-ch5", furi: "たんぱあ vs たこ（じゅうりょうつきかため）", jp: "タンパー vs たこ（重量突き固め）", romaji: "tanpaa vs tako (juryou tsukikatame)", id_text: "Tamper (plat logam, hentakkan) vs Taco (beban", desc: "タンパー = plat datar logam di ujung gagang panjang, dihentakkan memadatkan aspal/tanah. たこ = beban masif dijatuhkan ke tanah untuk memadatkan dengan beratnya.", _origIndex: 413 },
  { id: 629, category: "doboku_doko", source: "jac-ch3", furi: "だむこうじちすいりすい", jp: "ダム工事の目的：治水 vs 利水", romaji: "damu kouji: chisui vs risui", id_text: "Tujuan bendungan: tahan banjir vs manfaatkan air", desc: "治水=tahan banjir: tampung air saat hujan besar, atur debit. 利水=manfaatkan air stabil untuk pertanian, industri, 水力発電. Jepang punya 3000+ bendungan. Mandor:「洪水吐きゲートの点検して」(cek pintu spillway bendungan).", _origIndex: 620 },
  { id: 630, category: "doboku_doko", source: "jac-ch6", furi: "とんねるのよんしゅるいこうほうでぶんるい", jp: "トンネルの4種類（工法で分類）", romaji: "tonneru no yonshurui kouhou de bunrui", id_text: "4 jenis terowongan berdasarkan metode konstruksi", desc: "①山岳トンネル = NATM di batu keras gunung. ②開削トンネル = gali dari permukaan → bangun → timbun. ③シールドトンネル = mesin shield + segmen panel, tanah lunak. ④推進トンネル = pipa ditekan masuk tanah via dongkrak dari立坑.", _origIndex: 621 },
  { id: 631, category: "doboku_doko", source: "jac-ch3", furi: "なこうほうさんがくとんねるさんようそ", jp: "NATM工法（山岳トンネル）", romaji: "NATM kouhou sangaku tonneru san youso", id_text: "Metode NATM terowongan gunung — 3 elemen penyangga", desc: "NATM: gali gunung dengan peledakan/mesin. 3 penyangga: ①吹付けコンクリート=semprot beton ②鋼製支保工=rangka baja ③ロックボルト=baut pengikat batu. Mandor:「吹付け後にボルト打って」(pasang baut setelah semprot beton).", _origIndex: 622 },
  { id: 632, category: "doboku_doko", source: "jac-ch3", furi: "しいるどとんねるこうほうたてこうせぐめんと", jp: "シールドトンネル工法（立坑・セグメント）", romaji: "shiirudo tonneru kouhou tatekou segumento", id_text: "Terowongan shield: tanah lunak & bawah bangunan", desc: "Prosedur: ①Bangun 立坑(poros vertikal) ②Shield menggali ③Pasang セグメント(panel beton/besi) di belakang mesin. Mandor:「セグメント組み立て確認して」(cek pemasangan segmen).", _origIndex: 623 },
  { id: 633, category: "doboku_doko", source: "jac-ch3", furi: "きょうりょうこうじしゅるいとかぶこうじょうぶこう", jp: "橋梁工事：種類と下部工・上部工", romaji: "kyouryou kouji shurui to kabukou joubukou", id_text: "Pekerjaan jembatan: 6 jenis + 2 tahapan utama", desc: "Jenis: 桁橋・トラス・アーチ・ラーメン・斜張橋・吊橋. 下部工=fondasi penopang → 上部工=badan jembatan. Metode: ベント, ケーブルエレクション, 送り出し, フローティングクレーン. Mandor:「下部工の出来形検査入ります」(inspeksi fondasi jembatan).", _origIndex: 624 },
  { id: 634, category: "doboku_doko", source: "jac-ch3", furi: "かいよどぼくこうじのとくちょとしゅよしせつ", jp: "海洋土木工事の特徴と主要施設", romaji: "kaiyo doboku kouji no tokucho to shuyo shisetsu", id_text: "Pekerjaan sipil laut: fasilitas & alat kerja utama", desc: "Bangun di laut/sungai: pelabuhan, bandara laut, jembatan laut, terowongan bawah laut. Alat: ①作業船=kapal kerja ②潜水士=penyelam ③alat ukur batimetri. Mandor:「作業船の位置確認してから開始して」(cek posisi kapal kerja).", _origIndex: 625 },
  { id: 638, category: "doboku_doko", source: "jac-ch3", furi: "どこうじのさぎょうろくしゅるい", jp: "土工事の作業6種類", romaji: "do kouji no sagyou rokushurui", id_text: "6 jenis pekerjaan tanah", desc: "①掘削=gali tanah/batu (発破). ②積込み・運搬=muat残土. ③盛り土/切り土=tambah/potong tanah. ④埋め戻し=isi kembali. ⑤締固め=padatkan. ⑥法面=stabilisasi lereng. Mandor:「残土の運搬、記録つけて」(catat pengangkutan残土).", _origIndex: 629 },
  { id: 640, category: "doboku_hoso", source: "jac-ch3", furi: "ほそうこうじのよんそうこうぞうきそうをわすれずに", jp: "舗装工事の4層構造", romaji: "hosou kouji no yonsoukouzou (kisou wo wasurezu ni)", id_text: "4 lapisan jalan beraspal — jangan lupa lapisan 3", desc: "①路床=dasar terbawah, digali±1m. ②路盤=batu pecah dipadatkan. ③基層=aspal pertama (アスファルトフィニッシャー). ④表層=aspal atas, tahan air. 基層 jangan terlupa! Mandor:「路盤後に基層打って」(base dulu lalu aspal ke-3).", _origIndex: 631 },
  { id: 641, category: "doboku_doko", source: "jac-ch3", furi: "とびこうじのろくしゅるい", jp: "とび工事の6種類", romaji: "tobi kouji no rokushurui", id_text: "6 jenis pekerjaan tobi (ahli kerja ketinggian)", desc: "Pekerjaan tali baja di ketinggian. 6 jenis: 足場とび(perancah), 鉄骨とび(rangka baja), 橋梁とび(jembatan), 重量とび(mesin berat), 送電とび(menara listrik), 町場とび(rumah). Mandor:「足場の壁つなぎ確認して」(cek pengikat perancah).", _origIndex: 632 },
  { id: 649, category: "doboku_doko", source: "jac-ch3", furi: "かいよどぼくのよんこうじしゅんせつうめたてがんぺきぼおはていけえそん", jp: "海洋土木の4工事", romaji: "kaiyo doboku no yon kouji: shunsetsu umetate ganpeki boohatei keeson", id_text: "4 pekerjaan sipil laut: keruk/reklamasi/dermaga", desc: "①浚渫=keruk dasar laut/sungai dengan 浚渫船. ②埋立=timbun tanah→lahan baru. ③岸壁=dermaga: sheet pile+tiang. ④防波堤=pemecah gelombang: batu+ケーソン(kotak beton). Mandor:「ケーソンの据付位置確認して」(cek posisi caisson).", _origIndex: 640 },
  { id: 670, category: "doboku_doko", source: "jac-ch4", furi: "やりかたみずぬきみずもりじなわはりみずいと", jp: "遣り方・水貫・水盛り・地縄張り・水糸", romaji: "yarikata / mizunuki / mizumori / jinawahari / mizuito", id_text: "5 istilah yarkata — pagar referensi pra-konstruksi", desc: "遣り方=pagar sementara pasak+papan untuk posisi & ketinggian bangunan. 水貫=papan horizontal. 水盛り=tentukan referensi horizontal. 地縄張り=tandai pondasi. 水糸=benang referensi. Mandor:「遣り方を絶対に動かすな」.", _origIndex: 661 },
  { id: 672, category: "doboku_doko", source: "jac-ch4", furi: "もりとだんぎりしめかためてんあつうめもどしつきがため", jp: "盛り土・段切り・締固め・転圧・埋戻し・突固め", romaji: "morito / dangiri / shimekatame / ten'atsu / umemodoshi / tsukigatame", id_text: "6 istilah operasi tanah dasar", desc: "盛り土=timbunan. 段切り=gali bertangga di lereng. 締固め=padatkan tanah. 転圧=padatkan dengan alat berat. 埋め戻し=isi kembali setelah pekerjaan bawah tanah. 突き固め=padatkan dengan ランマ. Mandor:「埋め戻しは締固めをしっかりやれよ」.", _origIndex: 663 },
  { id: 673, category: "doboku_doko", source: "jac-ch4", furi: "ろばんろしょうひょうそう", jp: "路盤・路床・表層（舗装土工事3語）", romaji: "roban / roshou / hyousou (doukouji)", id_text: "3 lapisan perkerasan jalan — atas ke tanah dasar", desc: "表層=lapisan paling atas perkerasan aspal. 路盤=lapisan di atas 路床 menyebarkan beban. 路床=lapisan tanah dasar penopang perkerasan sekitar 1m dari permukaan. Mandor:「路盤の厚みを設計通りに確保してくれよ」.", _origIndex: 664 },
  { id: 674, category: "doboku_doko", source: "jac-ch4", furi: "じなわはりねぎりねいれながさすぼり", jp: "地縄はり・根切り・根入れ長さ・素掘り", romaji: "jinawahari / negiri / neirenagasa / subori", id_text: "4 istilah pra/pasca penggalian pondasi", desc: "地縄はり=tandai batas pondasi di tanah. 根切り=gali dengan alat berat hingga dasar pondasi. 根入れ長さ=kedalaman pondasi ke ujung. 素掘り=galian tanpa 土留め jika tanah kokoh. Mandor:「根入れ長さが設計値に達しているか確認して」.", _origIndex: 665 },
  { id: 676, category: "doboku_haisui", source: "jac-ch4", furi: "ばしょうちうつ", jp: "場所打ち・打つ（打設）", romaji: "bashouchi / utsu (dasetsu)", id_text: "2 istilah pengecoran beton di lokasi kerja", desc: "場所打ち/現場打ち=mengecor beton langsung di lokasi, bukan precast. 打つ/打設する=terminologi untuk menuang beton ke dalam cetakan. Mandor:「コンクリートを打設する前に型枠を必ず確認して」.", _origIndex: 667 },
  { id: 677, category: "doboku_doko", source: "jac-ch4", furi: "よぼりすきとりとこずけくいまさらいだんばね", jp: "余堀り・鋤取り・床付け・杭間さらい・段跳ね", romaji: "yobori / sukitori / tokozuke / kuimasarai / danbane", id_text: "5 istilah presisi penggalian & dasar pondasi", desc: "余堀り=galian lebih untuk ruang kerja. 鋤取り=ratakan dasar galian. 床付け=finishing dasar secara presisi. 杭間さらい=bersihkan tanah di antara tiang. 段跳ね=angkat tanah bertahap ke atas. Mandor:「床付けは慎重にやれよ」.", _origIndex: 668 },
  { id: 715, category: "doboku_hoso", source: "jac-ch3", furi: "どぼくこうじとくちょ", jp: "土木工事（どぼくこうじ）の特徴", romaji: "doboku kouji tokucho", id_text: "Karakteristik pekerjaan sipil", desc: "土木工事=berhadapan dengan alam (laut, sungai, gunung). Jenis: ダム, 河川, 道路, トンネル, 橋梁, 鉄道, 上下水道, 災害復旧. Berbeda dari 建築工事. Mandor:「河川工事の安全確認からだ」(mulai dari cek keselamatan kerja sungai).", _origIndex: 706 },
  { id: 750, category: "doboku_doko", source: "jac-gakka2", furi: "しきならしさぎょう", jp: "敷き均し作業（しきならしさぎょう）", romaji: "shiki narashi sagyou", id_text: "Pekerjaan penghamparan dan perataan material", desc: "Menyebarkan dan meratakan material (aspal, agregat, tanah) secara merata menggunakan mesin paver/finisher. Di proyek: berbeda dari 盛り土 (menumpuk tanah) dan 積み込み (memuat).", _origIndex: 741 },
  { id: 1247, category: "doboku_haisui", source: "vocab-supplementary", furi: "こうかんくい", jp: "鋼管杭", romaji: "koukan kui", id_text: "Tiang pancang pipa baja", desc: "例: 軟弱地盤では鋼管杭を支持層まで打ち込む。→ Pada tanah lunak, tiang pipa baja dipancang hingga lapisan pendukung. Jenis tiang pracetak berbahan baja, kuat menahan beban lateral.", _origIndex: 1225 },
  { id: 1269, category: "doboku_haisui", source: "vocab-supplementary", furi: "えきじょうか", jp: "液状化", romaji: "ekijou ka", id_text: "Likuefaksi / pencairan tanah", desc: "例: 地震時に砂質地盤が液状化すると、構造物が沈下・傾斜する恐れがある。→ Likuefaksi (液状化) terjadi saat gempa bumi menyebabkan tanah berpasir jenuh air kehilangan kekuatan dan berperilaku seperti cairan.", _origIndex: 1247 },
  { id: 1270, category: "doboku_haisui", source: "vocab-supplementary", furi: "じたいりょく", jp: "地耐力", romaji: "ji tairyoku", id_text: "Daya dukung tanah", desc: "例: 建物を建てる前に地耐力を確認し、必要に応じて地盤改良を行う。→ Daya dukung tanah (地耐力) adalah kemampuan tanah menahan beban dari struktur di atasnya. Diukur melalui uji N-value (ボーリング調査) atau uji plat beban.", _origIndex: 1248 }
];
